#!/usr/bin/env python3import numpy as npimport matplotlib.pyplot as pltn = 100x = np.linspace(0, np.pi, n)sinx = np.sin(x)cos_from_sinx = np.gradient(sinx, x)cos_numpy = np.cos(x)# sin(x) - linia ciągłaplt.plot(x, sinx, linestyle="-", label=" f(x)=sin(x)")# cos(x) z pochodnej i cos(x) z numpy - linie przerywaneplt.plot(x, cos_from_sinx, linestyle="--", label="f'(x) numerical")plt.plot(x, cos_numpy, linestyle=':', label="f'(x) analytical")plt.xlabel("x")plt.title("sin(x) derivative")plt.ylabel("value")plt.grid(True)plt.legend()plt.savefig('sinx-ok.png', dpi=300, bbox_inches='tight')plt.show()